static double riemann (const double * right, const double * left,
         double Delta, double * f, int len,
         double dtmax)
{
  double fr[len], fl[len], er[2], el[2];
  flux (right, fr, er);
  flux (left, fl, el);
  double ap = ( (er[1]) > (el[1]) ? (er[1]) : (el[1])); ap = ( ap > 0. ? ap : 0.);
  double am = ( (er[0]) < (el[0]) ? (er[0]) : (el[0])); am = ( am < 0. ? am : 0.);
  double a = ( ap > (-am) ? ap : (-am));

  if (a > 0.) {
    for (int i = 0; i < len; i++)
      f[i] = (ap*fl[i] - am*fr[i] + ap*am*(right[i] - left[i]))/(ap - am);
    double dt = CFL*Delta/a;
    if (dt < dtmax)
      dtmax = dt;
  }
  else
    for (int i = 0; i < len; i++)
      f[i] = 0.;
  return dtmax;
}

